const merged = github.list_pull_requests({ state: "merged" });
const total = merged.length;
const repos = [...new Set(merged.map(p => p.repo))];
const sample = merged[0];
({ total, repos, keys: Object.keys(sample || {}), sample });
"}

{"code":"
const closers = merged.filter(p => p.closes_linear);
const summary = closers.map(p => ({ repo: p.repo, num: p.number, title: p.title, closes: p.closes_linear }));
({ count: closers.length, summary });
"}

{"code":"
const results = closers.map(p => {
  const issue = github.create_issue({
    repo: "acme/web",
    title: "Verify: " + p.title
  });
  return { from: `${p.repo}#${p.number}`, closes: p.closes_linear, issue };
});
({ opened: results.length, results });
"}
